# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, websocket, path):
        self.websocket = websocket
        self.path = path
        self.inventory = defaultdict(int)

    async def notify(self, message):
        if self.websocket.open:
            await self.websocket.send(json.dumps(message))


class GameServer:
    def __init__(self):
        self.players = {}
        self.loop = asyncio.get_event_loop()

    async def register(self, websocket, path):
        player = Player(websocket, path)
        self.players[websocket] = player
        await player.notify({"action": "connect", "message": "Connected to the server successfully"})

    async def unregister(self, websocket):
        player = self.players[websocket]
        await player.notify({"action": "disconnect", "message": "Disconnected from the server"})
        self.players.pop(websocket)

    async def distribute_item(self, websocket, item, ownership):
        self.players[websocket].inventory[item] += ownership
        await self.players[websocket].notify({"action": "update", "message": f"{item} x {ownership} added to your inventory"})

    async def transfer_item(self, from_player, to_player, item, quantity):
        if from_player.inventory[item] < quantity:
            await from_player.notify({"action": "error", "message": "Not enough item in inventory"})
            return
        from_player.inventory[item] -= quantity
        to_player.inventory[item] += quantity
        await from_player.notify({"action": "update", "message": f"You sent {quantity} of {item} to {to_player.path}"})
        await to_player.notify({"action": "update", "message": f"You received {quantity} of {item} from {from_player.path}"})

    async def process(self, websocket, path, request):
        if request.get("action") == "trade":
            to_player = self.players[request['to_player']]
            from_player = self.players[websocket]
            await self.transfer_item(from_player, to_player, request['item'], request['quantity'])

        elif request.get("action") == "distribute":
            await self.distribute_item(websocket, request['item'], request['quantity'])

    async def serve(self, websocket, path):
        await self.register(websocket, path)
        try:
            async for message in websocket:
                data = json.loads(message)
                asyncio.ensure_future(self.process(websocket, path, data))
        finally:
            await self.unregister(websocket)

    def run(self):
        start_server = websockets.serve(self.serve, 'localhost', 8765)
        self.loop.run_until_complete(start_server)
        self.loop.run_forever()

if __name__ == "__main__":
    server = GameServer()
    server.run()